require_once __DIR__ . '/../includes/functions.php';
require_admin();
if($_SERVER['REQUEST_METHOD']==='POST'){ require_post_csrf(); try{ OrderService::updateStatus((int)$_POST['order_id'], $_POST['order_status'] ?? 'Pending'); set_flash('success','Order status updated.'); }catch(Throwable $e){ set_flash('danger',$e->getMessage()); } redirect('admin/manage_orders.php'); }
$status=$_GET['status'] ?? ''; $q=trim($_GET['q'] ?? ''); $orders=OrderService::all($status ?: null,$q ?: null); $selected=(int)($_GET['order_id'] ?? 0); $order=$selected ? OrderService::find($selected) : null; $pageTitle='Manage Orders'; $activePage='orders'; require __DIR__.'/../includes/header.php';
?>
<main class="container-fluid admin-shell"><div class="row g-4"><aside class="col-lg-2"><?php require __DIR__.'/../includes/sidebar.php'; ?></aside><section class="col-lg-10"><h1 class="section-title mb-4">Order Management</h1><form class="card form-card p-3 mb-4 no-loader" method="get"><div class="row g-3"><div class="col-md-5"><input name="q" class="form-control" placeholder="Search by order/customer" value="<?= e($q) ?>"></div><div class="col-md-4"><select name="status" class="form-select"><option value="">All Status</option><?php foreach(['Pending','Processing','Shipped','Delivered','Cancelled'] as $s): ?><option <?= $status===$s?'selected':'' ?>><?= $s ?></option><?php endforeach; ?></select></div><div class="col-md-3"><button class="btn btn-primary w-100">Filter</button></div></div></form><?php if($order): ?><div class="card form-card mb-4"><div class="card-body"><h5>Order #<?= (int)$order['id'] ?> Details</h5><p class="mb-2"><strong>Customer:</strong> <?= e($order['customer_name']) ?> (<?= e($order['customer_email']) ?>)</p><p class="mb-2"><strong>Billing:</strong> <?= nl2br(e($order['billing_address'])) ?></p><p class="mb-2"><strong>Payment:</strong> <?= e($order['payment_method']) ?> / <?= e($order['payment']['payment_status'] ?? 'Pending') ?><?php if(!empty($order['payment']['transaction_id'])): ?> / Txn: <?= e($order['payment']['transaction_id']) ?><?php endif; ?></p><div class="table-responsive"><table class="table"><thead><tr><th>Product</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead><tbody><?php foreach($order['items'] as $it): ?><tr><td><?= e($it['product_name']) ?></td><td><?= (int)$it['quantity'] ?></td><td><?= money($it['price']) ?></td><td><?= money((float)$it['price']*(int)$it['quantity']) ?></td></tr><?php endforeach; ?></tbody></table></div><form method="post" class="row g-2 align-items-end no-loader"><?= csrf_input() ?><input type="hidden" name="order_id" value="<?= (int)$order['id'] ?>"><div class="col-md-4"><label class="form-label">Update Status</label><select name="order_status" class="form-select"><?php foreach(['Pending','Processing','Shipped','Delivered','Cancelled'] as $s): ?><option <?= $order['order_status']===$s?'selected':'' ?>><?= $s ?></option><?php endforeach; ?></select></div><div class="col-md-3"><button class="btn btn-primary">Update</button></div></form></div></div><?php endif; ?><div class="card table-card"><div class="table-responsive"><table class="table align-middle mb-0"><thead class="table-light"><tr><th>Order</th><th>Customer</th><th>Total</th><th>Payment</th><th>Status</th><th>Date</th><th></th></tr></thead><tbody><?php foreach($orders as $o): ?><tr><td>#<?= (int)$o['id'] ?></td><td><?= e($o['customer_name']) ?><br><small><?= e($o['customer_email']) ?></small></td><td><?= money($o['total_amount']) ?></td><td><?= e($o['payment_method']) ?><br><small><?= e($o['payment_status'] ?? 'Pending') ?></small></td><td><?= order_status_badge($o['order_status']) ?></td><td><?= e(date('d M Y',strtotime($o['order_date']))) ?></td><td><a class="btn btn-sm btn-outline-primary" href="?order_id=<?= (int)$o['id'] ?>">View</a></td></tr><?php endforeach; if(!$orders): ?><tr><td colspan="7" class="text-center text-muted py-4">No orders found.</td></tr><?php endif; ?></tbody></table></div></div></section></div></main>
